// ============ WebSockets ============

export interface EventsServerEvents {
  mcp_status: McpServerStatus,
  mcp_servers: McpServersSnapshot,
  workspace_files_changed: WorkspaceFilesChanged
}

export interface EventsClientEvents {
  ping: Ping
}

export interface EventsSocket {
  readonly socket: WebSocket
  send<K extends keyof EventsClientEvents>(event: K, data: EventsClientEvents[K]): Effect.Effect<void, ZynkNetworkError>
  on<K extends keyof EventsServerEvents>(event: K): Stream.Stream<EventsServerEvents[K], ZynkNetworkError>
  close: Effect.Effect<void>
}

export const connectEvents = (): Effect.Effect<EventsSocket, ZynkNetworkError, ZynkClient> =>
  Effect.gen(function* () {
    const ws = yield* openWebSocket("events")
    return {
      socket: ws,
      send<K extends keyof EventsClientEvents>(event: K, data: EventsClientEvents[K]) {
        return Effect.try({
          try: () => ws.send(JSON.stringify({ event, data })),
          catch: (cause) =>
            new ZynkNetworkError({ url: ws.url, cause }),
        })
      },
      on<K extends keyof EventsServerEvents>(event: K) {
        return Stream.async<EventsServerEvents[K], ZynkNetworkError>((emit) => {
          const listener = (ev: MessageEvent) => {
            try {
              const parsed = JSON.parse(ev.data) as { event: string; data: unknown }
              if (parsed.event === event) {
                void emit.single(parsed.data as EventsServerEvents[K])
              }
            } catch (cause) {
              void emit.fail(new ZynkNetworkError({ url: ws.url, cause }))
            }
          }
          ws.addEventListener("message", listener)
          return Effect.sync(() => ws.removeEventListener("message", listener))
        })
      },
      close: Effect.sync(() => ws.close()),
    }
  })
